      style={{
        width,
        height,
        outline: selected ? "2px solid #f5c842" : "none",
        outlineOffset: 2,
      }}
      className={`
        rounded-lg border-2 border-[#cccccc] bg-white flex flex-col justify-between p-1 flex-shrink-0
        ${selected ? "-translate-y-2" : ""}
        transition-transform duration-100
      `}
    >
